from datetime import datetime

def get_chinese_zodiac(birthdate_str):
    birthdate = datetime.strptime(birthdate_str, "%m-%d-%Y")

    for entry in CHINESE_ZODIAC_YEARS:
        start = datetime.strptime(entry["start_date"], "%m-%d-%Y")
        end = datetime.strptime(entry["end_date"], "%m-%d-%Y")
        if start <= birthdate <= end:
            return {
                "zodiac": entry["zodiac"],
                "element": entry["element"],
                "year": entry["year"],
            }

    return None